const { loteId } = context;

const estado = validaYActualizaEstadoLote(loteId);
return estado;

function validaYActualizaEstadoLote(loteId) {
  let estadoBatch = { ok: true, records: 0, processed: 0, status: "FINISHED" };
  if(loteId){

    //El lote de renovación...
    doCmd({
      cmd: "LoadEntity",
      data:{
        entity: "Batch",
            fields: "status",
            filter: `id=${loteId}`
      }
    })

    if(LoadEntity.ok){
      const estado = LoadEntity.outData.status ?? "";
      if(estado === "PENDING"){
        doCmd({ cmd: "SetBatchResults", data:{ batchId: loteId } });
      }
    }

    //El de tarificación
    doCmd({"cmd":"LoadEntities","data":{"entity":"Batch","filter":`status = 'PENDING' AND name like 'QUOTELOTE%-${loteId}%'`}});
    const resultado = LoadEntities.outData ?? [];
    if(resultado.length > 0){
      resultado.forEach(x => {
        doCmd({ cmd: "SetBatchResults", data:{ batchId: x.id } });
        doCmd({ cmd: "RepoBatch", data:{ operation: "GET", filter: `id = ${x.id}` } });
        estadoBatch = RepoBatch.outData?.[0] ?? { ok:false, records: 0, processed: 0, status: "PENDING" };
        if(!estadoBatch.ok)
          estadoBatch.ok = true;
      });      
    }    

  }
  return estadoBatch;
}

